from flask import request, jsonify

def validate_and_deserialize_user_registration():
    data = request.get_json()

    if not isinstance(data, dict):
        return jsonify({"error": "Invalid JSON format"}), 400

    required_fields = ['name', 'email', 'password']
    for field in required_fields:
        if field not in data:
            return jsonify({"error": f"Missing field: {field}"}), 400
        if not isinstance(data[field], str):
            return jsonify({"error": f"Field '{field}' must be a string"}), 400

    name = data['name']
    email = data['email']
    password = data['password']

    return {
        "name": name,
        "email": email,
        "password": password
    }, 200

import pytest

def celsius_to_fahrenheit(celsius):
    return (celsius * 9/5) + 32

def fahrenheit_to_celsius(fahrenheit):
    return (fahrenheit - 32) * 5/9

@pytest.mark.parametrize("celsius, expected_fahrenheit", [
    (0, 32),      # Freezing point
    (100, 212),   # Boiling point
    (37, 98.6),   # Body temperature
    (-40, -40),   # Equal temperature in both scales
    (20, 68)      # Room temperature
])
def test_celsius_to_fahrenheit(celsius, expected_fahrenheit):
    assert celsius_to_fahrenheit(celsius) == expected_fahrenheit

@pytest.mark.parametrize("fahrenheit, expected_celsius", [
    (32, 0),      # Freezing point
    (212, 100),   # Boiling point
    (98.6, 37),   # Body temperature
    (-40, -40),   # Equal temperature in both scales
    (68, 20)      # Room temperature
])
def test_fahrenheit_to_celsius(fahrenheit, expected_celsius):
    assert fahrenheit_to_celsius(fahrenheit) == expected_celsius

